const b = $input.first().json.body || $input.first().json;
if (!b.client_id || !b.pillar_id) throw new Error('client_id and pillar_id required');
return [{ json: {
  task_id: `repurpose_${Date.now()}_${Math.random().toString(36).slice(2,8)}`,
  client_id: b.client_id,
  pillar_id: b.pillar_id,
  pillar_type: b.pillar_type || 'blog_post',
  platforms: b.platforms || ['linkedin', 'twitter', 'instagram', 'tiktok', 'email', 'video_script'],
  content_url: b.content_url || null,
  auto_publish: b.auto_publish || false,
  started_at: new Date().toISOString()
} }];

